UPDATE biz_partner_application
SET status = '승인', admin_reply = #{adminReply}, reviewed_at = NOW()
WHERE id = #{id}

UPDATE biz_partner_application
SET status = '미승인', admin_reply = #{adminReply}, reviewed_at = NOW()
where id = #{id}

UPDATE member
SET partner_status = #{status},
    partner_grade = #{grade}
    
        
            , partner_approved_at = NOW()
        
        
            , partner_approved_at = NULL
        
    
WHERE id COLLATE utf8mb4_unicode_ci = #{memberId}

UPDATE member
SET partner_grade = #{grade}
WHERE id COLLATE utf8mb4_unicode_ci = #{memberId}
    AND partner_status = '승인'
